var currentUID = flow.get('activeUID') || '';
var incomingUID = msg.payload.uid;
if (incomingUID === currentUID) return null;
flow.set('activeUID', incomingUID);
msg.topic = `SELECT * FROM accounts WHERE uid = '${incomingUID}'`;
msg.uid = incomingUID;
return msg;

var uid = msg.uid;
var rows = msg.payload;

if (!rows || rows.length === 0) {
    flow.set('activeUID', '');
    var declinedResult = { status: 'declined', reason: 'Card not registered' };
    var uiDeclined = { type: 'declined', reason: 'Card not registered' };
    node.send([
        { payload: JSON.stringify(declinedResult), topic: 'ledger/result' },
        null,
        { payload: uiDeclined }
    ]);
    return;
}

var account = rows[0];

if (account.status !== 'active') {
    flow.set('activeUID', '');
    var frozenResult = { status: 'declined', reason: 'Account frozen' };
    var uiFrozen = { type: 'declined', reason: 'Account frozen' };
    node.send([
        { payload: JSON.stringify(frozenResult), topic: 'ledger/result' },
        null,
        { payload: uiFrozen }
    ]);
    return;
}

flow.set('activeAccount', account);
flow.set('activeUID', '');

var espResult = { status: 'approved', name: account.name, balance: account.balance };
var histMsg = { topic: `SELECT * FROM transactions WHERE uid = '${uid}' ORDER BY timestamp DESC LIMIT 20`, account: account };

node.send([
    { payload: JSON.stringify(espResult), topic: 'ledger/result' },
    histMsg,
    { payload: account }
]);

var data = msg.payload;

if (data.type === 'declined') {
    return msg;  
}

var account = data;
msg.payload = { type: 'account', uid: account.uid, name: account.name, balance: account.balance, status: account.status, created_at: account.created_at };
return msg;

var data = msg.payload;
if (!data || !data.action) return null;
var account = flow.get('activeAccount');
if (!account) {
    node.send([null, { payload: { type: 'txn_result', success: false, message: 'No active account.' } }]);
    return;
}
var amount = parseFloat(data.amount);
if (!amount || amount <= 0) return null;
var newBalance;
if (data.action === 'deposit') {
    newBalance = account.balance + amount;
} else if (data.action === 'withdraw') {
    if (amount > account.balance) {
        node.send([null, { payload: { type: 'txn_result', success: false, message: 'Insufficient funds.' } }]);
        return;
    }
    newBalance = account.balance - amount;
}
newBalance = Math.round(newBalance * 100) / 100;
msg.txnData = { uid: account.uid, type: data.action, amount: amount, balance_after: newBalance, teller: 'operator' };
msg.topic = `INSERT INTO transactions (uid, type, amount, balance_after, teller) VALUES ('${account.uid}', '${data.action}', ${amount}, ${newBalance}, 'operator')`;
account.balance = newBalance;
flow.set('activeAccount', account);
return [msg, null];

var txn = msg.txnData;
msg.topic = `UPDATE accounts SET balance = ${txn.balance_after} WHERE uid = '${txn.uid}'`;
return msg;

var txn = msg.txnData;
var typeLabel = txn.type.charAt(0).toUpperCase() + txn.type.slice(1);
var account = flow.get('activeAccount');
var espResult = { status: 'approved', name: account.name, balance: txn.balance_after };
var uiResult = { type: 'txn_result', success: true, message: `${typeLabel} of Rs. ${txn.amount.toFixed(2)} successful.`, newBalance: txn.balance_after };
var histMsg = { topic: `SELECT * FROM transactions WHERE uid = '${txn.uid}' ORDER BY timestamp DESC LIMIT 20` };
node.send([
    { payload: JSON.stringify(espResult), topic: 'ledger/result' },
    { payload: uiResult },
    histMsg
]);

flow.set('espOnline', true);
flow.set('lastHeartbeat', new Date().toLocaleString());
return null;

var uid = msg.payload.uid;
flow.set('pendingUID', uid);
msg.payload = { type: 'uid_scanned', uid: uid };
return msg;

var data = msg.payload;
if (!data || !data.action) return null;
if (data.action === 'start_enroll') return [{ payload: 'start', topic: 'ledger/cmd/enroll' }, null, null, null, null];
if (data.action === 'enroll') {
    msg.enrollData = { uid: data.uid, name: data.name, balance: data.balance };
    msg.topic = `INSERT OR IGNORE INTO accounts (uid, name, balance) VALUES ('${data.uid}', '${data.name.replace(/'/g,"''")}', ${data.balance})`;
    return [null, msg, null, null, null];
}
if (data.action === 'load_accounts') {
    msg.topic = 'SELECT * FROM accounts ORDER BY name ASC';
    return [null, null, msg, null, null];
}
if (data.action === 'set_status') {
    msg.statusData = { uid: data.uid, status: data.status };
    msg.topic = `UPDATE accounts SET status = '${data.status}' WHERE uid = '${data.uid}'`;
    return [null, null, null, msg, null];
}
if (data.action === 'delete') {
    msg.deleteUID = data.uid;
    msg.topic = `DELETE FROM accounts WHERE uid = '${data.uid}'`;
    return [null, null, null, null, msg];
}
if (data.action === 'edit') {
    msg.topic = `UPDATE accounts SET name = '${data.name.replace(/'/g,"''")}', balance = ${data.balance} WHERE uid = '${data.uid}'`;
    msg.statusData = { uid: data.uid, status: '' };
    return [null, null, null, msg, null];
}
return null;
